/*
 * var_dot1dBridge():
 *   This function is called every time the agent gets a request for
 *   a scalar variable that might be found within your mib section
 *   registered above.  It is up to you to do the right thing and
 *   return the correct value.
 *     You should also correct the value of "var_len" if necessary.
 *
 *   Please see the documentation for more information about writing
 *   module extensions, and check out the examples in the examples
 *   and mibII directories.
 */
unsigned char *
var_dot1dBridge(struct variable *vp,
                oid     *name,
                size_t  *length,
                int     exact,
                size_t  *var_len,
                WriteMethod **write_method)
{
    /* variables we may use later */
    static long long_ret;
    static u_long ulong_ret;
    static unsigned char strMac[CAPA_MAC_BYTE_NUM];
    static unsigned char string[256];
    uint32 holdCnt;
//    static unsigned char string[SPRINT_MAX_LEN];

    u_long tmp;
    struct timeval tv;
#ifdef CONFIG_SYS_PROTO_STP
    sys_stp_mst_info_t mstInfo;
    sys_stp_info_t stpInfo;
#endif

    if (header_generic(vp,name,length,exact,var_len,write_method)
                                  == MATCH_FAILED )
    return NULL;

#ifdef CONFIG_SYS_PROTO_STP
    SYS_MEM_CLEAR(mstInfo);
    SYS_MEM_CLEAR(stpInfo);
    sal_stp_mstInfo_get(0,&mstInfo);
    sal_stp_info_get(&stpInfo);
#endif

  /*
   * this is where we do the value assignments for the mib results.
   */
    switch(vp->magic) {
    case DOT1DBASEBRIDGEADDRESS:
       {
        sys_mac_t mac;
        sal_sys_macAddr_get(&mac);
        memcpy(strMac, mac.octet, CAPA_MAC_BYTE_NUM);
        *var_len = CAPA_MAC_BYTE_NUM;
        return (u_char*) strMac;
       }

    case DOT1DBASENUMPORTS:
      //  sal_physic_port_num_get(0, &ulong_ret);
        ulong_ret = SYS_USER_PORT_NUM(SYS_DEV_ID_DEFAULT);
        return (u_char*) &ulong_ret;

    case DOT1DBASETYPE:
        long_ret = TRANSPARENT_BRIDGE ;   /*only support*/
        return (u_char*) &long_ret;

    case DOT1DSTPPROTOCOLSPECIFICATION:
        long_ret = IEEE8021d_PROTO;     /*only support*/
        return (u_char*) &long_ret;

#ifdef CONFIG_SYS_PROTO_STP
    case DOT1DSTPTIMESINCETOPOLOGYCHANGE:
        ulong_ret = mstInfo.tcTimer * 100;
        return (u_char*) &ulong_ret;

    case DOT1DSTPTOPCHANGES:
        ulong_ret = mstInfo.tcTimes;
        return (u_char*) &ulong_ret;

    case DOT1DSTPDESIGNATEDROOT:
        sprintf(string,"%d/%.2X:%.2X:%.2X:%.2X:%.2X:%.2X",mstInfo.rootPriority.designatedBridgeId.priority, \
                                                                                      mstInfo.rootPriority.designatedBridgeId.addr[0],
                                                                                      mstInfo.rootPriority.designatedBridgeId.addr[1],
                                                                                      mstInfo.rootPriority.designatedBridgeId.addr[2],
                                                                                      mstInfo.rootPriority.designatedBridgeId.addr[3],
                                                                                      mstInfo.rootPriority.designatedBridgeId.addr[4],
                                                                                      mstInfo.rootPriority.designatedBridgeId.addr[5]);
        *var_len = strlen(string); /*this when some byte is equal to 0,may generate bug.*/
        return (u_char*) &string;

    case DOT1DSTPROOTCOST:
        ulong_ret = mstInfo.rootPriority.internalRootPathCost;
        return (u_char*) &ulong_ret;

    case DOT1DSTPROOTPORT:
        ulong_ret = LP2UP(mstInfo.rootPortId.number - 1);
        return (u_char*) &ulong_ret;

    case DOT1DSTPMAXAGE:
        ulong_ret = stpInfo.maximumAge * SYS_HUNDREDTHS_SECOND;
        return (u_char*) &ulong_ret;

    case DOT1DSTPHELLOTIME:
        ulong_ret = stpInfo.helloTime * SYS_HUNDREDTHS_SECOND;
        return (u_char*) &ulong_ret;

    case DOT1DSTPHOLDTIME:
        #ifdef CONFIG_SYS_PROTO_STP
        sal_stp_txHoldCount_get(&holdCnt);
        #endif
         ulong_ret = 10/holdCnt * SYS_HUNDREDTHS_SECOND;
        return (u_char*) &ulong_ret;

    case DOT1DSTPFORWARDDELAY:
        ulong_ret = stpInfo.forwardDelay * SYS_HUNDREDTHS_SECOND;
        return (u_char*) &ulong_ret;

    case DOT1DSTPPRIORITY:
        *write_method = write_dot1dStpPriority;
        /*mstp id = 0*/
        sal_stp_priority_get(&ulong_ret);
        return (u_char*) &ulong_ret;

    case DOT1DSTPBRIDGEMAXAGE:
        *write_method = write_dot1dStpBridgeMaxAge;
        sal_stp_maximumAge_get(&ulong_ret);
        ulong_ret = ulong_ret * SYS_HUNDREDTHS_SECOND;
        return (u_char*) &ulong_ret;

    case DOT1DSTPBRIDGEHELLOTIME:
        *write_method = write_dot1dStpBridgeHelloTime;
        sal_stp_helloTime_get(&ulong_ret);
        ulong_ret = ulong_ret * SYS_HUNDREDTHS_SECOND;
        return (u_char*) &ulong_ret;

    case DOT1DSTPBRIDGEFORWARDDELAY:
        *write_method = write_dot1dStpBridgeForwardDelay;
        sal_stp_forwardDelay_get(&ulong_ret);
        ulong_ret = ulong_ret * SYS_HUNDREDTHS_SECOND;
        return (u_char*) &ulong_ret;
#endif

        /*dot1dTpLearnedEntryDiscards*/
    case DOT1DTPLEARNEDENTRYDISCARDS:
        sal_mib_dot1dTpLearnedEntryDiscards_get(&ulong_ret);
        return (u_char*) &ulong_ret;

    case DOT1DTPAGINGTIME:
        *write_method = write_dot1dTpAgingTime;
        sal_l2_aging_get(&ulong_ret);
        return (u_char*) &ulong_ret;

    default:
      ERROR_MSG("");
    }
    return NULL;
}


/*
 * var_dot1dBasePortTable():
 *   Handle this table separately from the scalar value case.
 *   The workings of this are basically the same as for var_dot1dBridge above.
 */

unsigned char *
var_dot1dBasePortTable(struct variable *vp,
            oid     *name,
            size_t  *length,
            int     exact,
            size_t  *var_len,
            WriteMethod **write_method)
{
    /* variables we may use later */
    static long long_ret;
    static u_long ulong_ret;
   // static unsigned char string[SPRINT_MAX_LEN];
    static oid objid[MAX_OID_LEN];

    unsigned long   index;
    rtk_stat_port_cntr_t portcntr;

    /*
   * This assumes that the table is a 'simple' table.
   *    See the implementation documentation for the meaning of this.
   *    You will need to provide the correct value for the TABLE_SIZE parameter
   *
   * If this table does not meet the requirements for a simple table,
   *    you will need to provide the replacement code yourself.
   *    Mib2c is not smart enough to write this for you.
   *    Again, see the implementation documentation for what is required.
   */
    *write_method = NULL;
    if (header_simple_table(vp,name,length,exact,var_len,write_method, LP2UP(LOGIC_PORT_END) + 1)
                                                == MATCH_FAILED )
        return NULL;

    index = vp->namelen >= *length ? 0 : UP2LP(name[vp->namelen]);

    if (exact) /* GET packet for one instance */
    {
        if (*length != 12 )
            return NULL;
    }
    else /* Get-Next packet */
    {
        if (-1 == header_logicPort(&index, vp, name, length))
            return NULL;
    }

    if (IS_LOGIC_PORT_INVALID(index))
        return NULL;

    *var_len = sizeof(long);
    DEBUGMSGTL(("[RTK]", "index = %d\n", index));



    /*
   * this is where we do the value assignments for the mib results.
   */

    switch(vp->magic) {
    case DOT1DBASEPORT:
        ulong_ret = LP2UP(index);
        return (u_char*) &ulong_ret;

    case DOT1DBASEPORTIFINDEX:
        ulong_ret = LP2UP(index);
        return (u_char*) &ulong_ret;

    case DOT1DBASEPORTCIRCUIT:
      /*
     * Currently only Ethernet interfaces are supported and hence returning
     * the OID {0, 0}.
     */
      objid[0] = 0;
      objid[1] = 0;
      *var_len = 2*sizeof(objid[0]);
       return (u_char*) &objid;

    case DOT1DBASEPORTDELAYEXCEEDEDDISCARDS:
       //sal_mib_dot1d_delayexceededdiscards_get(index, &ulong_ret);
       ulong_ret = 0;
       return (u_char*) &ulong_ret;

    case DOT1DBASEPORTMTUEXCEEDEDDISCARDS:
        sal_mib_dot3StatsFrameTooLongs_get(index, &ulong_ret);
       // sal_mib_etherStatsOverSizePkts_get(index, &ulong_ret);
        return (u_char*) &ulong_ret;

    default:
      ERROR_MSG("");
    }
    return NULL;
}
/*
 * var_dot1dTpFdbTable():
 *   Handle this table separately from the scalar value case.
 *   The workings of this are basically the same as for var_dot1dBridge above.
 */
unsigned char *
var_dot1dTpFdbTable(struct variable *vp,
            oid     *name,
            size_t  *length,
            int     exact,
            size_t  *var_len,
            WriteMethod **write_method)
{
    tpfdb_entry_t *tpfdb;
    uint32 vlanId;
    char *pMac;
    int     macLen, i;
    char   macAddr[CAPA_MAC_BYTE_NUM];

    static uint32 macNum = 0;

    /*
   * This assumes that the table is a 'simple' table.
   *    See the implementation documentation for the meaning of this.
   *    You will need to provide the correct value for the TABLE_SIZE parameter
   *
   * If this table does not meet the requirements for a simple table,
   *    you will need to provide the replacement code yourself.
   *    Mib2c is not smart enough to write this for you.
   *    Again, see the implementation documentation for what is required.
   */
    if (0 != AGUTIL_advance_index_name(vp, name, length, exact)) {
       return NULL;
    }

    if (exact) {

        if (*length != 17)
            return NULL;

        macAddr[0] = (char)name[11];
        macAddr[1] = (char)name[12];
        macAddr[2] = (char)name[13];
        macAddr[3] = (char)name[14];
        macAddr[4] = (char)name[15];
        macAddr[5] = (char)name[16];

        tpfdb = qbridge_getTpfdbEntry_byMac(macAddr);
    } else {

        if (11 == *length)
        {
            qbridge_tpfdb_entry_get(&macNum, TRUE);
            if(macNum == 0)
                return NULL;

            osal_memset(macAddr, 0 , CAPA_MAC_BYTE_NUM);
            tpfdb = qbridge_tpfdb_scanFirst();
        }
        else
        {
            macAddr[0] = (char)name[11];
            macAddr[1] = (char)name[12];
            macAddr[2] = (char)name[13];
            macAddr[3] = (char)name[14];
            macAddr[4] = (char)name[15];
            macAddr[5] = (char)name[16];

          qbridge_tpfdb_scanAccessInit();
          while((tpfdb = qbridge_tpfdb_scanAccessNext()) != NULL){
            if (0 == osal_memcmp(macAddr , tpfdb->mac, CAPA_MAC_BYTE_NUM))
             {
                 tpfdb = qbridge_tpfdb_scanAccessNext();
                 break;
             }
           }

         }

        if (tpfdb) {
            *length = 11;
            for(i = 0; i < CAPA_MAC_BYTE_NUM; i++)
            {
                name[(*length)++] = tpfdb->mac[i];
            }
        }
    }

    if (tpfdb == NULL) {
        return NULL;
    }

    *var_len = sizeof(long_ret);
    /*
   * this is where we do the value assignments for the mib results.
   */

    switch(vp->magic) {
    case DOT1DTPFDBADDRESS:
        *var_len = 6 ;
        return (u_char*) tpfdb->mac;

    case DOT1DTPFDBPORT:
        long_ret = tpfdb->port;
        return (u_char *)&long_ret;
    case DOT1DTPFDBSTATUS:
        long_ret = tpfdb->status;
        return (u_char*) &long_ret;

    default:
      ERROR_MSG("");
    }

    return NULL;
}
