int
write_dot1dStaticAddress(int      action,
            u_char   *var_val,
            u_char   var_val_type,
            size_t   var_val_len,
            u_char   *statP,
            oid      *name,
            size_t   name_len)
{
    char value;
    int size;
    int32 index, i;
    uint8 isStatic, isZero = TRUE;
    static char mac[6] = {0,0,0,0,0,0};
    uint32 mode;
    sys_logic_port_t port;
    sys_l2_entry_t macEntry;
    sys_l2_entry_t *pPrev = NULL;
    sys_l2_entry_t *pCurr = NULL;

    SYS_MEM_CLEAR(macEntry);

    switch ( action ) {
        case RESERVE1:
          if (var_val_type != ASN_OCTET_STR) {
              fprintf(stderr, "write to dot1dBridge not ASN_OCTET_STR\n");
              return SNMP_ERR_WRONGTYPE;
          }
          if (var_val_len !=  CAPA_MAC_BYTE_NUM) {
              fprintf(stderr,"write to dot1dBridge: bad length\n");
              return SNMP_ERR_WRONGLENGTH;
          }

       for (i = 0; i < CAPA_MAC_BYTE_NUM; i++)
       {
            if (0 != var_val[i])
            {
                 isZero = FALSE;
                 break;
            }
       }

        if ((0x01 & var_val[0]) || isZero)
            return SNMP_ERR_WRONGVALUE;

        for (i = 0; i < 6; i++)
        {
            if (name[name_len-1-6+i] > 255)
                return SNMP_ERR_INCONSISTENTVALUE;

            mac[i] = name[name_len-1-6+i];
        }

        i = 0;
        while (NULL != (pCurr = sal_l2_staticMacNext_ret(pPrev)))
        {
            if (0 == osal_memcmp(mac, &pCurr->mac,CAPA_MAC_BYTE_NUM))
            {
                osal_memcpy(&macEntry, pCurr, sizeof(sys_l2_entry_t));
                break;
            }

            pPrev = pCurr;

            i++;
        }

          if (i == CAPA_L2_STATIC_MAC_NUM)
            return SNMP_ERR_INCONSISTENTVALUE;

          break;

        case RESERVE2:
          size  = var_val_len;
          value = * (char *) var_val;

          SYS_SNMP_ERR_CHK(sal_l2_staticMac_del(&macEntry), SNMP_ERR_RESOURCEUNAVAILABLE);
          osal_memcpy(&macEntry.mac, var_val, CAPA_MAC_BYTE_NUM);
          SYS_SNMP_ERR_CHK(sal_l2_staticMac_add(&macEntry), SNMP_ERR_RESOURCEUNAVAILABLE);
          break;

        case FREE:
             /* Release any resources that have been allocated */
          break;

        case ACTION:
             /*
              * The variable has been stored in 'value' for you to use,
              * and you have just been asked to do something with it.
              * Note that anything done here must be reversable in the UNDO case
              */
          break;

        case UNDO:
             /* Back out any changes made in the ACTION case */
          break;

        case COMMIT:
             /*
              * Things are working well, so it's now safe to make the change
              * permanently.  Make sure that anything done here can't fail!
              */
          break;
    }
    return SNMP_ERR_NOERROR;
}
